// ═══════════════════════════════════════════════════════
// 解析与生成
// ═══════════════════════════════════════════════════════
function parseEntries(str) {
  return str.split(',').filter(Boolean).map(e => {
    const [word, pos, meaning] = e.trim().split(':');
    return { word: word.trim(), pos: pos.trim(), meaning: meaning.trim() };
  });
}

function generate() {
  const roots = [];
  let totalRootWords = 0;

  for (let i = 0; i < ROOTS.length; i++) {
    const r = ROOTS[i];
    const [id, meaning, origin, color, level, wordsStr] = r;
    const words = parseEntries(wordsStr);
    totalRootWords += words.length;
    roots.push({ id, root: id, meaning, origin, color, level, words });
  }

  const supplement = {};
  let totalSuppWords = 0;
  for (const [topic, wordsStr] of Object.entries(SUPPLEMENT)) {
    const words = parseEntries(wordsStr);
    totalSuppWords += words.length;
    supplement[topic] = words;
  }

  const db = {
    version: '1.0',
    generatedAt: new Date().toISOString(),
    stats: {
      rootCount: roots.length,
      rootWordCount: totalRootWords,
      supplementWordCount: totalSuppWords,
      totalWordCount: totalRootWords + totalSuppWords,
    },
    roots,
    supplement,
  };

  console.log(`Generated vocabulary database:`);
  console.log(`  Roots: ${db.stats.rootCount}`);
  console.log(`  Root-based words: ${db.stats.rootWordCount}`);
  console.log(`  Supplementary words: ${db.stats.supplementWordCount}`);
  console.log(`  Total: ${db.stats.totalWordCount}`);

  const outPath = path.join(__dirname, '..', 'src', 'data', 'wordDatabase.json');
  fs.writeFileSync(outPath, JSON.stringify(db, null, 0)); // compact JSON
  console.log(`\nWritten to: ${outPath}`);
  console.log(`File size: ${(fs.statSync(outPath).size / 1024).toFixed(1)} KB`);
}

generate();
